-- PocketKuma canonical SQLite schema (Knex migration end-state).
-- Regenerate src/db/kuma.db via: bun scripts/build/generate-kuma-db.ts

PRAGMA foreign_keys = OFF;

CREATE TABLE `docker_host` (`id` integer not null primary key autoincrement, `user_id` integer not null, `docker_daemon` varchar(255), `docker_type` varchar(255), `name` varchar(255));
CREATE TABLE `group` (`id` integer not null primary key autoincrement, `name` varchar(255) not null, `created_date` datetime not null default CURRENT_TIMESTAMP, `public` boolean not null default '0', `active` boolean not null default '1', `weight` integer not null default '1000', `status_page_id` integer);
CREATE TABLE `user` (`id` integer not null primary key autoincrement, `username` varchar(255) not null, `password` varchar(255), `active` boolean not null default '1', `timezone` varchar(150), `twofa_secret` varchar(64), `twofa_status` boolean not null default '0', `twofa_last_token` varchar(6));
CREATE UNIQUE INDEX `user_username_unique` on `user` (`username`);
CREATE TABLE `incident` (`id` integer not null primary key autoincrement, `title` varchar(255) not null, `content` text not null, `style` varchar(30) not null default 'warning', `created_date` datetime not null default CURRENT_TIMESTAMP, `last_updated_date` datetime, `pin` boolean not null default '1', `active` boolean not null default '1', `status_page_id` integer);
CREATE TABLE `maintenance` (`id` integer not null primary key autoincrement, `title` varchar(150) not null, `description` text not null, `user_id` integer, `active` boolean not null default '1', `strategy` varchar(50) not null default 'single', `start_date` datetime, `end_date` datetime, `start_time` time, `end_time` time, `weekdays` varchar(250) default '[]', `days_of_month` text default '[]', `interval_day` integer, `cron` text, `timezone` varchar(255), `duration` integer, `last_start_date` datetime, foreign key(`user_id`) references `user`(`id`) on delete SET NULL on update CASCADE);
CREATE INDEX `maintenance_active_index` on `maintenance` (`active`);
CREATE INDEX `manual_active` on `maintenance` (`strategy`, `active`);
CREATE INDEX `maintenance_user_id` on `maintenance` (`user_id`);
CREATE TABLE `maintenance_status_page` (`id` integer not null primary key autoincrement, `status_page_id` integer not null, `maintenance_id` integer not null, foreign key(`status_page_id`) references `status_page`(`id`) on delete CASCADE on update CASCADE, foreign key(`maintenance_id`) references `maintenance`(`id`) on delete CASCADE on update CASCADE);
CREATE TABLE `monitor_group` (`id` integer not null primary key autoincrement, `monitor_id` integer not null, `group_id` integer not null, `weight` integer not null default '1000', `send_url` boolean not null default '0', `custom_url` text, foreign key(`monitor_id`) references `monitor` (`id`) on delete CASCADE on update CASCADE, foreign key(`group_id`) references `group` (`id`) on delete CASCADE on update CASCADE);
CREATE INDEX `fk` on `monitor_group` (`monitor_id`, `group_id`);
CREATE TABLE `monitor_maintenance` (`id` integer not null primary key autoincrement, `monitor_id` integer not null, `maintenance_id` integer not null, foreign key(`monitor_id`) references `monitor` (`id`) on delete CASCADE on update CASCADE, foreign key(`maintenance_id`) references `maintenance` (`id`) on delete CASCADE on update CASCADE);
CREATE INDEX `maintenance_id_index2` on `monitor_maintenance` (`maintenance_id`);
CREATE INDEX `monitor_id_index` on `monitor_maintenance` (`monitor_id`);
CREATE TABLE `notification` (`id` integer not null primary key autoincrement, `name` varchar(255), `active` boolean not null default '1', `user_id` integer, `is_default` boolean not null default '0', `config` text);
CREATE TABLE `monitor_notification` (`id` integer not null primary key autoincrement, `monitor_id` integer not null, `notification_id` integer not null, foreign key(`monitor_id`) references `monitor` (`id`) on delete CASCADE on update CASCADE, foreign key(`notification_id`) references `notification` (`id`) on delete CASCADE on update CASCADE);
CREATE INDEX `monitor_notification_index` on `monitor_notification` (`monitor_id`, `notification_id`);
CREATE TABLE `tag` (`id` integer not null primary key autoincrement, `name` varchar(255) not null, `color` varchar(255) not null, `created_date` datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE `monitor_tag` (`id` integer not null primary key autoincrement, `monitor_id` integer not null, `tag_id` integer not null, `value` text, foreign key(`monitor_id`) references `monitor` (`id`) on delete CASCADE on update CASCADE, foreign key(`tag_id`) references `tag` (`id`) on delete CASCADE on update CASCADE);
CREATE TABLE `notification_sent_history` (`id` integer not null primary key autoincrement, `type` varchar(50) not null, `monitor_id` integer not null, `days` integer not null);
CREATE UNIQUE INDEX `notification_sent_history_type_monitor_id_days_unique` on `notification_sent_history` (`type`, `monitor_id`, `days`);
CREATE INDEX `good_index` on `notification_sent_history` (`type`, `monitor_id`, `days`);
CREATE TABLE `setting` (`id` integer not null primary key autoincrement, `key` varchar(200) not null, `value` text, `type` varchar(20));
CREATE UNIQUE INDEX `setting_key_unique` on `setting` (`key`);
CREATE TABLE `status_page_cname` (`id` integer not null primary key autoincrement, `status_page_id` integer, `domain` varchar(255) not null, foreign key(`status_page_id`) references `status_page` (`id`) on delete CASCADE on update CASCADE);
CREATE UNIQUE INDEX `status_page_cname_domain_unique` on `status_page_cname` (`domain`);
CREATE TABLE `api_key` (`id` integer not null primary key autoincrement, `key` varchar(255) not null, `name` varchar(255) not null, `user_id` integer not null, `created_date` datetime not null default CURRENT_TIMESTAMP, `active` boolean not null default '1', `expires` datetime default null, foreign key(`user_id`) references `user` (`id`) on delete CASCADE on update CASCADE);
CREATE TABLE `remote_browser` (`id` integer not null primary key autoincrement, `name` varchar(255) not null, `url` varchar(255) not null, `user_id` integer);
CREATE TABLE `monitor_tls_info` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `monitor_id` integer NOT NULL, `info_json` text, FOREIGN KEY (`monitor_id`) REFERENCES `monitor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE `proxy` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `user_id` integer NOT NULL, `protocol` varchar(10) NOT NULL, `host` varchar(255) NOT NULL, `port` integer, `auth` boolean NOT NULL, `username` varchar(255) NULL, `password` varchar(255) NULL, `active` boolean NOT NULL DEFAULT '1', `default` boolean NOT NULL DEFAULT '0', `created_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX `proxy_user_id` on `proxy` (`user_id`);
CREATE TABLE `domain_expiry` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `last_check` datetime, `domain` varchar(255) NOT NULL, `expiry` datetime, `last_expiry_notification_sent` integer DEFAULT null);
CREATE UNIQUE INDEX `domain_expiry_domain_unique` on `domain_expiry` (`domain`);
CREATE TABLE `heartbeat` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `important` boolean NOT NULL DEFAULT '0', `monitor_id` integer NOT NULL, `status` integer NOT NULL, `msg` text, `time` datetime NOT NULL, `ping` bigint, `duration` integer NOT NULL DEFAULT '0', `down_count` integer NOT NULL DEFAULT '0', `end_time` datetime NULL DEFAULT null, `retries` integer NOT NULL DEFAULT '0', `response` text NULL DEFAULT null, FOREIGN KEY (`monitor_id`) REFERENCES `monitor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE INDEX `monitor_time_index` on `heartbeat` (`monitor_id`, `time`);
CREATE INDEX `heartbeat_monitor_id_index` on `heartbeat` (`monitor_id`);
CREATE INDEX `monitor_important_time_index` on `heartbeat` (`monitor_id`, `time`) where important = 1;
CREATE INDEX `heartbeat_important_index` on `heartbeat` (`important`) where important = 1;
CREATE TABLE `stat_minutely` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `monitor_id` integer NOT NULL, `timestamp` integer NOT NULL, `ping` float NOT NULL, `up` integer NOT NULL, `down` integer NOT NULL, `ping_min` float NOT NULL DEFAULT '0', `ping_max` float NOT NULL DEFAULT '0', `extras` text DEFAULT null, FOREIGN KEY (`monitor_id`) REFERENCES `monitor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX `stat_minutely_monitor_id_timestamp_unique` on `stat_minutely` (`monitor_id`, `timestamp`);
CREATE TABLE `stat_daily` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `monitor_id` integer NOT NULL, `timestamp` integer NOT NULL, `ping` float NOT NULL, `up` integer NOT NULL, `down` integer NOT NULL, `ping_min` float NOT NULL DEFAULT '0', `ping_max` float NOT NULL DEFAULT '0', `extras` text DEFAULT null, FOREIGN KEY (`monitor_id`) REFERENCES `monitor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX `stat_daily_monitor_id_timestamp_unique` on `stat_daily` (`monitor_id`, `timestamp`);
CREATE TABLE `stat_hourly` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `monitor_id` integer NOT NULL, `timestamp` integer NOT NULL, `ping` float NOT NULL, `ping_min` float NOT NULL DEFAULT '0', `ping_max` float NOT NULL DEFAULT '0', `up` integer NOT NULL, `down` integer NOT NULL, `extras` text DEFAULT null, FOREIGN KEY (`monitor_id`) REFERENCES `monitor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX `stat_hourly_monitor_id_timestamp_unique` on `stat_hourly` (`monitor_id`, `timestamp`);
CREATE TABLE `monitor` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `name` varchar(150), `active` boolean NOT NULL DEFAULT '1', `user_id` integer, `interval` integer NOT NULL DEFAULT '20', `url` text, `type` varchar(20), `weight` integer DEFAULT '2000', `hostname` varchar(255), `port` integer, `created_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, `keyword` varchar(255), `maxretries` integer NOT NULL DEFAULT '0', `ignore_tls` boolean NOT NULL DEFAULT '0', `upside_down` boolean NOT NULL DEFAULT '0', `maxredirects` integer NOT NULL DEFAULT '10', `accepted_statuscodes_json` text NOT NULL DEFAULT '["200-299"]', `dns_resolve_type` varchar(5), `dns_resolve_server` varchar(255), `dns_last_result` text, `retry_interval` integer NOT NULL DEFAULT '0', `push_token` varchar(32), `method` text NOT NULL DEFAULT 'GET', `body` text DEFAULT null, `headers` text DEFAULT null, `basic_auth_user` text DEFAULT null, `basic_auth_pass` text DEFAULT null, `docker_host` integer, `docker_container` varchar(255), `proxy_id` integer, `expiry_notification` boolean DEFAULT '1', `mqtt_topic` text, `mqtt_success_message` varchar(255), `mqtt_username` varchar(255), `mqtt_password` varchar(255), `database_connection_string` varchar(2000), `database_query` text, `auth_method` varchar(250), `auth_domain` text, `auth_workstation` text, `grpc_url` varchar(255) DEFAULT null, `grpc_protobuf` text DEFAULT null, `grpc_body` text DEFAULT null, `grpc_metadata` text DEFAULT null, `grpc_method` text DEFAULT null, `grpc_service_name` text DEFAULT null, `grpc_enable_tls` boolean NOT NULL DEFAULT '0', `radius_username` varchar(255), `radius_password` varchar(255), `radius_calling_station_id` varchar(50), `radius_called_station_id` varchar(50), `radius_secret` varchar(255), `resend_interval` integer NOT NULL DEFAULT '0', `packet_size` integer NOT NULL DEFAULT '56', `game` varchar(255), `http_body_encoding` varchar(25), `description` text DEFAULT null, `tls_ca` text DEFAULT null, `tls_cert` text DEFAULT null, `tls_key` text DEFAULT null, `parent` integer, `invert_keyword` boolean NOT NULL DEFAULT '0', `json_path` text, `expected_value` varchar(255), `kafka_producer_topic` varchar(255), `kafka_producer_brokers` text, `kafka_producer_ssl` boolean NOT NULL DEFAULT '0', `kafka_producer_allow_auto_topic_creation` boolean NOT NULL DEFAULT '0', `kafka_producer_sasl_options` text, `kafka_producer_message` text, `oauth_client_id` text DEFAULT null, `oauth_client_secret` text DEFAULT null, `oauth_token_url` text DEFAULT null, `oauth_scopes` text DEFAULT null, `oauth_auth_method` text DEFAULT null, `timeout` float NOT NULL DEFAULT '0', `gamedig_given_port_only` boolean NOT NULL DEFAULT '1', `mqtt_check_type` varchar(255) NOT NULL DEFAULT 'keyword', `remote_browser` integer NULL DEFAULT null, `snmp_oid` varchar(255) DEFAULT null, `snmp_version` text CHECK (`snmp_version` in('1' , '2c' , '3')) DEFAULT '2c', `json_path_operator` varchar(255) DEFAULT null, `cache_bust` boolean NOT NULL DEFAULT '0', `conditions` text NOT NULL DEFAULT '[]', `rabbitmq_nodes` text, `rabbitmq_username` varchar(255), `rabbitmq_password` varchar(255), `smtp_security` varchar(255) DEFAULT null, `ws_ignore_sec_websocket_accept_header` boolean NOT NULL DEFAULT '0', `ws_subprotocol` varchar(255) NOT NULL DEFAULT '', `ping_count` integer NOT NULL DEFAULT '1', `ping_numeric` boolean NOT NULL DEFAULT '1', `ping_per_request_timeout` integer NOT NULL DEFAULT '2', `ip_family` varchar(4) DEFAULT null, `manual_status` integer, `oauth_audience` varchar(255) NULL DEFAULT null, `mqtt_websocket_path` varchar(255) NULL, `domain_expiry_notification` boolean DEFAULT '0', `save_response` boolean NOT NULL DEFAULT '0', `save_error_response` boolean NOT NULL DEFAULT '1', `response_max_length` integer NOT NULL DEFAULT '1024', `system_service_name` varchar(255), `subtype` varchar(10) NULL, `location` varchar(255) NULL, `protocol` varchar(20) NULL, `snmp_v3_username` varchar(255), `expected_tls_alert` varchar(50) DEFAULT null, `retry_only_on_status_code_failure` boolean NOT NULL DEFAULT '0', `screenshot_delay` integer NOT NULL DEFAULT '0', `bearer_token` text default null, `gamedig_token` text default null, FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, FOREIGN KEY (`docker_host`) REFERENCES `docker_host` (`id`), FOREIGN KEY (`proxy_id`) REFERENCES `proxy` (`id`), FOREIGN KEY (`parent`) REFERENCES `monitor` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, FOREIGN KEY (`remote_browser`) REFERENCES `remote_browser` (`id`));
CREATE INDEX `monitor_remote_browser_index` on `monitor` (`remote_browser`);
CREATE TABLE `status_page` (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `slug` varchar(255) NOT NULL, `title` varchar(255) NOT NULL, `description` text, `icon` varchar(255) NOT NULL, `theme` varchar(30) NOT NULL, `published` boolean NOT NULL DEFAULT '1', `search_engine_index` boolean NOT NULL DEFAULT '1', `show_tags` boolean NOT NULL DEFAULT '0', `password` varchar(255), `created_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, `modified_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, `footer_text` text, `custom_css` text, `show_powered_by` boolean NOT NULL DEFAULT '1', `analytics_id` varchar(255), `show_certificate_expiry` boolean NOT NULL DEFAULT '0', `auto_refresh_interval` integer DEFAULT '300', `analytics_script_url` varchar(255), `analytics_type` varchar(255) DEFAULT null, `show_only_last_heartbeat` boolean NOT NULL DEFAULT '0', `rss_title` varchar(255));
CREATE UNIQUE INDEX `status_page_slug_unique` on `status_page` (`slug`);

PRAGMA foreign_keys = ON;